const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, 
        HeadingLevel, AlignmentType, WidthType, ShadingType, BorderStyle,
        PageBreak, LevelFormat } = require('docx');
const fs = require('fs');

// 페이지 설정
const PAGE_WIDTH = 12240;
const CONTENT_WIDTH = 9360;

// 스타일 정의
const styles = {
  default: {
    document: {
      run: { font: "Arial", size: 24 }
    }
  },
  paragraphStyles: [
    {
      id: "Heading1",
      name: "Heading 1",
      basedOn: "Normal",
      next: "Normal",
      quickFormat: true,
      run: { size: 32, bold: true, font: "Arial", color: "1F4788" },
      paragraph: { spacing: { before: 480, after: 240 }, outlineLevel: 0 }
    },
    {
      id: "Heading2",
      name: "Heading 2",
      basedOn: "Normal",
      next: "Normal",
      quickFormat: true,
      run: { size: 28, bold: true, font: "Arial", color: "2E5C8A" },
      paragraph: { spacing: { before: 360, after: 180 }, outlineLevel: 1 }
    },
    {
      id: "Heading3",
      name: "Heading 3",
      basedOn: "Normal",
      next: "Normal",
      quickFormat: true,
      run: { size: 26, bold: true, font: "Arial", color: "4472C4" },
      paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 2 }
    }
  ]
};

// 넘버링 설정
const numbering = {
  config: [
    {
      reference: "bullets",
      levels: [
        {
          level: 0,
          format: LevelFormat.BULLET,
          text: "●",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } }
        },
        {
          level: 1,
          format: LevelFormat.BULLET,
          text: "○",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 1440, hanging: 360 } } }
        }
      ]
    },
    {
      reference: "numbers",
      levels: [
        {
          level: 0,
          format: LevelFormat.DECIMAL,
          text: "%1.",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } }
        }
      ]
    }
  ]
};

// 테이블 보더
const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };

// 섹션 생성 함수
function createCoverPage() {
  return [
    new Paragraph({ 
      spacing: { before: 3000 },
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ 
        text: "Physical AI for Engineers",
        size: 48,
        bold: true,
        color: "1F4788"
      })]
    }),
    new Paragraph({ 
      spacing: { before: 240, after: 120 },
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ 
        text: "제조 혁신의 기술적 이해",
        size: 36,
        color: "4472C4"
      })]
    }),
    new Paragraph({ 
      spacing: { before: 1200 },
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ 
        text: "1시간 기술 강의 자료",
        size: 24,
        color: "666666"
      })]
    }),
    new Paragraph({ 
      spacing: { before: 2400 },
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ 
        text: "대상: 엔지니어 / 기술인력",
        size: 22
      })]
    }),
    new Paragraph({ 
      spacing: { before: 120 },
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ 
        text: "목표: 피지컬 AI 개념 이해 및 기술 아키텍처 파악",
        size: 22
      })]
    })
  ];
}

function createTimelineTable() {
  return new Table({
    width: { size: 100, type: WidthType.PERCENTAGE },
    columnWidths: [1872, 5616, 1872],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 1872, type: WidthType.DXA },
            shading: { fill: "1F4788", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "시간", bold: true, color: "FFFFFF" })] 
            })]
          }),
          new TableCell({
            borders,
            width: { size: 5616, type: WidthType.DXA },
            shading: { fill: "1F4788", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "주제", bold: true, color: "FFFFFF" })] 
            })]
          }),
          new TableCell({
            borders,
            width: { size: 1872, type: WidthType.DXA },
            shading: { fill: "1F4788", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "슬라이드", bold: true, color: "FFFFFF" })] 
            })]
          })
        ]
      }),
      ...[
        ["00:00-10:00", "Opening: 문제 정의와 기술 맥락", "1-8"],
        ["10:00-25:00", "Part 1: 피지컬 AI 기술 아키텍처", "9-22"],
        ["25:00-40:00", "Part 2: 제조 시스템으로의 통합", "23-38"],
        ["40:00-50:00", "Part 3: 구현 사례와 기술 스택", "39-52"],
        ["50:00-60:00", "Closing: 엔지니어의 역할과 Q&A", "53-58"]
      ].map((row, idx) => {
        const bgColor = idx % 2 === 0 ? "F0F4F8" : "FFFFFF";
        return new TableRow({
          children: row.map((cell, cellIdx) => new TableCell({
            borders,
            width: { size: cellIdx === 1 ? 5616 : 1872, type: WidthType.DXA },
            shading: { fill: bgColor, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: cellIdx === 1 ? AlignmentType.LEFT : AlignmentType.CENTER,
              children: [new TextRun(cell)] 
            })]
          }))
        });
      })
    ]
  });
}

function createComparisonTable() {
  return new Table({
    width: { size: 100, type: WidthType.PERCENTAGE },
    columnWidths: [4680, 4680],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 4680, type: WidthType.DXA },
            shading: { fill: "E8F4F8", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "Traditional AI (디지털 AI)", bold: true })] 
            })]
          }),
          new TableCell({
            borders,
            width: { size: 4680, type: WidthType.DXA },
            shading: { fill: "E8F4E8", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            children: [new Paragraph({ 
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: "Physical AI (피지컬 AI)", bold: true })] 
            })]
          })
        ]
      }),
      ...[
        ["화면 속에 존재", "물리 세계에 구현"],
        ["정보 처리 및 분석", "직접 행동 및 조작"],
        ["센서 데이터 해석", "센서 + 액추에이터 통합"],
        ["의사결정 지원", "자율적 실행"],
        ["소프트웨어 중심", "HW + SW + 로보틱스 융합"]
      ].map((row, idx) => {
        const bgColor = idx % 2 === 0 ? "FFFFFF" : "F8F8F8";
        return new TableRow({
          children: row.map(cell => new TableCell({
            borders,
            width: { size: 4680, type: WidthType.DXA },
            shading: { fill: bgColor, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            children: [new Paragraph({ children: [new TextRun(cell)] })]
          }))
        });
      })
    ]
  });
}

// 문서 생성
const doc = new Document({
  styles,
  numbering,
  sections: [{
    properties: {
      page: {
        size: { width: PAGE_WIDTH, height: 15840 },
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 }
      }
    },
    children: [
      // 표지
      ...createCoverPage(),

      new Paragraph({ children: [new PageBreak()] }),

      // 목차
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("강의 구성")]
      }),
      new Paragraph({ 
        spacing: { after: 240 },
        children: [new TextRun("이 강의는 엔지니어의 관점에서 피지컬 AI의 기술적 메커니즘을 이해하고, 제조 현장 적용을 위한 실질적 지식을 제공합니다.")]
      }),
      createTimelineTable(),

      new Paragraph({ children: [new PageBreak()] }),

      // Opening
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("Opening: 문제 정의와 기술 맥락")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("한국 제조업이 직면한 3중 위기")]
      }),

      new Paragraph({
        numbering: { reference: "numbers", level: 0 },
        children: [new TextRun({ text: "노동력 위기: 숙련공 부족과 고령화", bold: true })]
      }),
      new Paragraph({
        spacing: { left: 720 },
        children: [new TextRun("제조 현장의 암묵지(Tacit Knowledge)가 사라지고 있습니다. 20-30년 경력의 숙련공이 보유한 '감'과 '노하우'를 디지털화하지 못하면 경쟁력이 급격히 하락합니다.")]
      }),

      new Paragraph({
        numbering: { reference: "numbers", level: 0 },
        children: [new TextRun({ text: "글로벌 공급망 재편: 효율성에서 안정성으로", bold: true })]
      }),
      new Paragraph({
        spacing: { left: 720 },
        children: [new TextRun("미-중 기술 패권 경쟁으로 Just-in-Time 시스템이 붕괴하고 있습니다. 친구 쇼어링(Friend-shoring)과 리쇼어링으로 글로벌 분업 구조가 근본적으로 재편되고 있습니다.")]
      }),

      new Paragraph({
        numbering: { reference: "numbers", level: 0 },
        children: [new TextRun({ text: "AI 전환: 제조 패러다임의 변화", bold: true })]
      }),
      new Paragraph({
        spacing: { left: 720, after: 360 },
        children: [new TextRun("제품의 정의, 생산 방식, 가치 사슬이 동시에 재편됩니다. 소프트웨어 정의 제품(Software-Defined Product), AI 기반 자율 생산, 데이터 기반 경쟁력이 새로운 표준이 됩니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("왜 지금 피지컬 AI인가?")]
      }),

      new Paragraph({
        spacing: { after: 240 },
        children: [new TextRun({ 
          text: "피지컬 AI는 이 3중 위기에 대한 기술적 해답입니다.",
          bold: true,
          color: "1F4788"
        })]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun("숙련공의 암묵지를 AI 모델로 학습하여 재현 가능")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun("자동화된 생산으로 인건비 의존도 감소 및 리쇼어링 경쟁력 확보")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun("실시간 데이터 기반 의사결정으로 제조 민첩성 확보")]
      }),

      new Paragraph({ children: [new PageBreak()] }),

      // Part 1
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("Part 1: 피지컬 AI 기술 아키텍처")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("1.1 피지컬 AI의 정의와 차별성")]
      }),

      new Paragraph({
        spacing: { after: 360 },
        children: [new TextRun({ 
          text: "\"병 속의 뇌(Brain in a Jar)에서 몸을 가진 뇌(Brain in a Body)로\"",
          italics: true,
          size: 26
        })]
      }),

      createComparisonTable(),

      new Paragraph({
        spacing: { before: 360, after: 240 },
        children: [new TextRun({ 
          text: "핵심 차이점:",
          bold: true
        })]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Embodiment (구현체): ", bold: true }), new TextRun("지능이 물리적 형태를 가짐")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Sensor-Motor Loop: ", bold: true }), new TextRun("인식→판단→행동의 실시간 피드백")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Physical Interaction: ", bold: true }), new TextRun("물리 세계를 직접 변경")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("1.2 피지컬 AI의 3대 핵심 기술")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_3,
        children: [new TextRun("① Perception (인식)")] 
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [new TextRun("물리 세계의 상태를 센싱하고 이해하는 기술")]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Vision System: ", bold: true }), new TextRun("3D 카메라, LiDAR, ToF 센서를 통한 공간 인식")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Tactile Sensing: ", bold: true }), new TextRun("압력, 진동, 온도 센서를 통한 촉각 정보")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Force/Torque Sensing: ", bold: true }), new TextRun("힘과 토크 측정으로 정밀 조작")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Multi-Modal Fusion: ", bold: true }), new TextRun("다중 센서 데이터 통합 및 해석")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_3,
        children: [new TextRun("② Cognition (판단)")] 
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [new TextRun("센서 데이터를 기반으로 상황을 이해하고 의사결정하는 AI 모델")]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Foundation Models: ", bold: true }), new TextRun("GPT-4, Claude 등 대규모 언어 모델")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Vision-Language Models: ", bold: true }), new TextRun("이미지와 텍스트를 동시에 이해 (GPT-4V, Gemini)")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Reinforcement Learning: ", bold: true }), new TextRun("시뮬레이션과 실제 환경에서 학습")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "World Models: ", bold: true }), new TextRun("물리 세계를 예측하고 시뮬레이션")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_3,
        children: [new TextRun("③ Action (행동)")] 
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [new TextRun("AI의 판단을 물리적 움직임으로 변환하는 로봇 시스템")]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Actuator Systems: ", bold: true }), new TextRun("서보모터, 공압/유압 시스템")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "End Effectors: ", bold: true }), new TextRun("그리퍼, 툴 체인저, 다관절 손")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Motion Planning: ", bold: true }), new TextRun("경로 계획 및 충돌 회피")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Control Systems: ", bold: true }), new TextRun("PID, MPC 등 실시간 제어 알고리즘")]
      }),

      new Paragraph({ children: [new PageBreak()] }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("1.3 시스템 아키텍처: Edge-Cloud 하이브리드")]
      }),

      new Paragraph({
        spacing: { after: 240 },
        children: [new TextRun("피지컬 AI는 실시간성과 확장성을 동시에 확보하기 위해 Edge-Cloud 하이브리드 아키텍처를 채택합니다.")]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Edge Computing (로컬 처리)", bold: true })]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("실시간 제어: <10ms 레이턴시로 즉각 반응")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("센서 데이터 전처리 및 필터링")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("경량 추론 모델 실행 (TensorRT, ONNX Runtime)")]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        children: [new TextRun({ text: "Cloud Computing (중앙 처리)", bold: true })]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("대규모 모델 학습 및 업데이트")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("전체 공장 데이터 분석 및 최적화")]
      }),
      new Paragraph({
        numbering: { reference: "bullets", level: 1 },
        children: [new TextRun("디지털 트윈 시뮬레이션")]
      }),

      new Paragraph({ children: [new PageBreak()] }),

      // Part 2
      new Paragraph({
        heading: HeadingLevel.HEADING_1,
        children: [new TextRun("Part 2: 제조 시스템으로의 통합")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun("2.1 제조 데이터 + 피지컬 AI = 새로운 패러다임")]
      }),

      new Paragraph({
        spacing: { after: 360 },
        children: [new TextRun({ 
          text: "\"공장이 하나의 거대한 로봇으로 진화한다\"",
          bold: true,
          color: "1F4788",
          size: 28
        })]
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [new TextRun("기존 제조 시스템은 각각의 기계가 독립적으로 작동했습니다. 피지컬 AI는 전체 공장을 하나의 통합된 사이버-물리 시스템(CPS)으로 변환합니다.")]
      }),

      new Paragraph({
        heading: HeadingLevel.HEADING_3,
        children: [new TextRun("제조 전 과정의 AI 통합")]
      }),

      new Paragraph({
        numbering: { reference: "numbers", level: 0 },
        children: [new TextRun({ text: "제품 설계 (Generative Design)", bold: true })]
      }),
      new Paragraph({
        spacing: { left: 720 },
        children: [new TextRun("AI가 수천 가지 설계안을 생성하고, 물리 시뮬레이션으로 검증 후 3D 프린팅 로봇이 실물 프로토타입 제작")]
      }),

      new Paragraph({
        numbering: { reference: "numbers", level: 0 },
        children: [new TextRun({ text: "생산 계획 (Predictive Scheduling)", bold: true })]
      }),
